    14|interface ChurnOutRiskProps {
    15|  positions: BondPosition[];
    16|}
    17|
    18|export function ChurnOutRisk({ positions }: ChurnOutRiskProps) {
    19|  const rankings = useNodeRankings(positions);
    20|
    21|  // Merge rankings with position data
    22|  const nodesWithRank: NodeWithRank[] = useMemo(() => {
    23|    if (rankings.length === 0) {
    24|      return [];
    25|    }
