    27|    return positions
    28|      .filter((pos) => pos.status === 'Active')
    29|      .map((position) => {
    30|        const ranking = rankings.find((r) => r.nodeAddress === position.nodeAddress);
    31|        if (!ranking) {
    32|          return null;
    33|        }
    34|        return {
    35|          ...ranking,
    36|          totalBond: position.bondAmount,
    37|          status: position.status,
    38|        };
    39|      })
    40|      .filter((n): n is NodeWithRank => n !== null)
    41|      .sort((a, b) => {
    42|        // Sort by bond amount (highest first)
    43|        const bondA = a.totalBond;
    44|        const bondB = b.totalBond;
    45|        return bondB - bondA;
    46|      });
